Method.Source:
/// <summary>
///  Freezes the form fields by updating the design when the data source is activated.
/// </summary>
/// <returns></returns>
public int active()
{
    int ret;

    ret = next active();

    ETGDMSIntegrationFormDesignHelper::updateDesignDMS(this);

    if(ETGACFParameters::find().EnableDMSIntegration == NoYes::Yes)
    {
        // Disable the control InventoryTracking_BatchNumGroupId
        FormRun formRun = this.formRun();
        FormStringControl Name_FirstName = formRun.control(formRun.controlId("Name_FirstName")) as FormStringControl;
        FormStringControl Name_MiddleName = formRun.control(formRun.controlId("Name_MiddleName")) as FormStringControl; 
        FormStringControl Name_LastName = formRun.control(formRun.controlId("Name_LastName")) as FormStringControl;
       //FormStringControl PersonNameGroup_LastNamePrefix = formRun.control(formRun.controlId("PersonNameGroup_LastNamePrefix")) as FormStringControl;

        if (Name_FirstName)
        {
            Name_FirstName.enabled(false);
        }
        if (Name_MiddleName)
        {
            Name_MiddleName.enabled(false);
        }
        if (Name_LastName)
        {
            Name_LastName.enabled(false);
        }

    }

    return ret;

}
